const crypto = require('crypto');

// Get input items (extracted data from previous node)
const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { error: 'No input data received' } }];
}

// Extract the data array from the first item
const rawData = items[0].json.data || items[0].json || [];

if (!Array.isArray(rawData) || rawData.length === 0) {
  return [{ json: { error: 'No valid data array found' } }];
}

// Compute file hash from raw data
const dataString = JSON.stringify(rawData);
const fileHash = crypto.createHash('sha256').update(dataString).digest('hex');

// Helper function to normalize values
function normalizeValue(value) {
  if (value === null || value === undefined || value === '') {
    return null;
  }

  // Convert to string for processing
  let strValue = String(value).trim();

  // Normalize comma-separated numbers (e.g., "1,234.56" -> 1234.56)
  if (/^[\d,]+\.?\d*$/.test(strValue)) {
    const numValue = parseFloat(strValue.replace(/,/g, ''));
    if (!isNaN(numValue)) {
      return numValue;
    }
  }

  // Detect and normalize date strings
  const datePatterns = [
    /^\d{4}-\d{2}-\d{2}$/,  // YYYY-MM-DD
    /^\d{2}\/\d{2}\/\d{4}$/,  // MM/DD/YYYY
    /^\d{2}-\d{2}-\d{4}$/,  // DD-MM-YYYY
  ];

  for (const pattern of datePatterns) {
    if (pattern.test(strValue)) {
      const date = new Date(strValue);
      if (!isNaN(date.getTime())) {
        return date.toISOString();
      }
    }
  }

  return value;
}

// Helper function to detect value type
function detectType(value) {
  if (value === null || value === undefined || value === '') {
    return 'null';
  }

  if (typeof value === 'number') {
    return Number.isInteger(value) ? 'integer' : 'float';
  }

  if (typeof value === 'boolean') {
    return 'boolean';
  }

  const strValue = String(value).trim();

  // Check for number
  if (/^-?[\d,]+\.?\d*$/.test(strValue)) {
    const num = parseFloat(strValue.replace(/,/g, ''));
    if (!isNaN(num)) {
      return Number.isInteger(num) ? 'integer' : 'float';
    }
  }

  // Check for date
  const date = new Date(strValue);
  if (!isNaN(date.getTime()) && strValue.length > 5) {
    return 'date';
  }

  // Check for boolean-like strings
  if (['true', 'false', 'yes', 'no', 'y', 'n'].includes(strValue.toLowerCase())) {
    return 'boolean';
  }

  return 'string';
}

// Detect headers
const firstRow = rawData[0];
const keys = Object.keys(firstRow);

// Check for header inconsistencies
const headerCandidates = keys.map(key => {
  return {
    original: key,
    normalized: key.trim().toLowerCase().replace(/[^a-z0-9_]/g, '_'),
    hasSpecialChars: /[^a-zA-Z0-9_\s]/.test(key),
    isEmpty: key.trim() === ''
  };
});

// Normalize data and collect statistics
const normalizedData = [];
const columnStats = {};
const rowHashes = new Set();
let duplicateCount = 0;

for (const key of keys) {
  columnStats[key] = {
    types: {},
    missingCount: 0,
    totalCount: rawData.length,
    uniqueValues: new Set(),
    mixedTypes: false
  };
}

for (let i = 0; i < rawData.length; i++) {
  const row = rawData[i];
  const normalizedRow = {};

  // Create row hash for duplicate detection
  const rowHash = crypto.createHash('md5').update(JSON.stringify(row)).digest('hex');
  if (rowHashes.has(rowHash)) {
    duplicateCount++;
    continue; // Skip duplicate rows
  }
  rowHashes.add(rowHash);

  for (const key of keys) {
    const rawValue = row[key];
    const normalizedValue = normalizeValue(rawValue);
    normalizedRow[key] = normalizedValue;

    // Update statistics
    const stats = columnStats[key];

    if (normalizedValue === null) {
      stats.missingCount++;
    } else {
      const type = detectType(normalizedValue);
      stats.types[type] = (stats.types[type] || 0) + 1;
      stats.uniqueValues.add(String(normalizedValue));
    }
  }

  normalizedData.push(normalizedRow);
}

// Determine type candidates and detect mixed types
for (const key of keys) {
  const stats = columnStats[key];
  const typeKeys = Object.keys(stats.types);

  if (typeKeys.length > 1) {
    stats.mixedTypes = true;
  }

  // Determine primary type (most common)
  let primaryType = 'string';
  let maxCount = 0;

  for (const [type, count] of Object.entries(stats.types)) {
    if (count > maxCount) {
      maxCount = count;
      primaryType = type;
    }
  }

  stats.primaryType = primaryType;
  stats.uniqueCount = stats.uniqueValues.size;
  delete stats.uniqueValues; // Remove set for JSON serialization
}

// Get clean sample rows (first 100)
const sampleRows = normalizedData.slice(0, 100);

// Prepare output
const output = {
  fileHash,
  totalRows: rawData.length,
  cleanRows: normalizedData.length,
  duplicateRows: duplicateCount,
  headerCandidates,
  columnStatistics: columnStats,
  sampleRows,
  summary: {
    columnsWithMixedTypes: keys.filter(k => columnStats[k].mixedTypes),
    columnsWithMissingValues: keys.filter(k => columnStats[k].missingCount > 0),
    headerIssues: headerCandidates.filter(h => h.hasSpecialChars || h.isEmpty)
  }
};

return [{ json: output }];

// Column Profiling Engine
// Profiles each column: nulls, types, uniqueness, cardinality, sequences, IDs, foreign keys

const items = $input.all();

if (!items || items.length === 0) {
  return [{ json: { error: 'No input data to profile' } }];
}

// Helper function to detect data type
function detectType(value) {
  if (value === null || value === undefined || value === '') return 'null';
  if (typeof value === 'number') return isNaN(value) ? 'null' : 'number';
  if (typeof value === 'boolean') return 'boolean';

  const str = String(value).trim();
  if (str === '') return 'null';

  // Check for number
  if (!isNaN(str) && !isNaN(parseFloat(str))) return 'number';

  // Check for date
  const datePatterns = [
    /^\d{4}-\d{2}-\d{2}$/,
    /^\d{2}\/\d{2}\/\d{4}$/,
    /^\d{4}\/\d{2}\/\d{2}$/
  ];
  if (datePatterns.some(pattern => pattern.test(str))) return 'date';

  // Check for email
  if (/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(str)) return 'email';

  // Check for URL
  if (/^https?:\/\/.+/.test(str)) return 'url';

  return 'string';
}

// Helper function to check if sequence is monotonic
function isMonotonic(values) {
  if (values.length < 2) return false;

  let increasing = true;
  let decreasing = true;

  for (let i = 1; i < values.length; i++) {
    if (values[i] <= values[i - 1]) increasing = false;
    if (values[i] >= values[i - 1]) decreasing = false;
  }

  return increasing || decreasing;
}

// Extract all column names from all items
const allColumns = new Set();
items.forEach(item => {
  Object.keys(item.json).forEach(col => allColumns.add(col));
});

// Profile each column
const columnProfiles = {};

allColumns.forEach(columnName => {
  const values = items.map(item => item.json[columnName]);
  const totalCount = values.length;

  // Count nulls
  const nullCount = values.filter(v => v === null || v === undefined || v === '').length;
  const nullPercentage = (nullCount / totalCount) * 100;

  // Detect type distribution
  const typeDistribution = {};
  values.forEach(value => {
    const type = detectType(value);
    typeDistribution[type] = (typeDistribution[type] || 0) + 1;
  });

  // Get dominant type
  const dominantType = Object.entries(typeDistribution)
    .filter(([type]) => type !== 'null')
    .sort((a, b) => b[1] - a[1])[0]?.[0] || 'unknown';

  // Count unique values
  const nonNullValues = values.filter(v => v !== null && v !== undefined && v !== '');
  const uniqueValues = new Set(nonNullValues.map(v => String(v)));
  const uniqueCount = uniqueValues.size;
  const uniquePercentage = nonNullValues.length > 0 ? (uniqueCount / nonNullValues.length) * 100 : 0;

  // Infer cardinality level
  let cardinalityLevel = 'unknown';
  if (uniqueCount === 0) {
    cardinalityLevel = 'empty';
  } else if (uniqueCount === 1) {
    cardinalityLevel = 'constant';
  } else if (uniqueCount === nonNullValues.length) {
    cardinalityLevel = 'unique';
  } else if (uniqueCount <= 10) {
    cardinalityLevel = 'low';
  } else if (uniquePercentage < 5) {
    cardinalityLevel = 'low';
  } else if (uniquePercentage < 50) {
    cardinalityLevel = 'medium';
  } else {
    cardinalityLevel = 'high';
  }

  // Check if potential ID
  const isPotentialId = (
    uniqueCount === nonNullValues.length &&
    uniqueCount > 0 &&
    (columnName.toLowerCase().includes('id') ||
     columnName.toLowerCase().includes('key') ||
     columnName.toLowerCase().includes('code'))
  );

  // Check if monotonic (for numeric values)
  let isMonotonicSequence = false;
  if (dominantType === 'number') {
    const numericValues = nonNullValues
      .map(v => parseFloat(v))
      .filter(v => !isNaN(v))
      .sort((a, b) => a - b);
    isMonotonicSequence = isMonotonic(numericValues);
  }

  // Store profile
  columnProfiles[columnName] = {
    columnName,
    totalCount,
    nullCount,
    nullPercentage: Math.round(nullPercentage * 100) / 100,
    typeDistribution,
    dominantType,
    uniqueCount,
    uniquePercentage: Math.round(uniquePercentage * 100) / 100,
    cardinalityLevel,
    isPotentialId,
    isMonotonic: isMonotonicSequence,
    sampleValues: Array.from(uniqueValues).slice(0, 5)
  };
});

// Detect foreign key candidates by comparing patterns across columns
const foreignKeyCandidates = {};

const columnNames = Object.keys(columnProfiles);
for (let i = 0; i < columnNames.length; i++) {
  const col1 = columnNames[i];
  const profile1 = columnProfiles[col1];

  // Skip if not a potential FK (must have reasonable cardinality)
  if (profile1.cardinalityLevel === 'constant' || profile1.cardinalityLevel === 'empty') continue;

  const candidates = [];

  for (let j = 0; j < columnNames.length; j++) {
    if (i === j) continue;

    const col2 = columnNames[j];
    const profile2 = columnProfiles[col2];

    // Check if col1 values are subset of col2 values (FK relationship)
    const values1 = new Set(items.map(item => String(item.json[col1])).filter(v => v && v !== 'null' && v !== 'undefined'));
    const values2 = new Set(items.map(item => String(item.json[col2])).filter(v => v && v !== 'null' && v !== 'undefined'));

    if (values1.size === 0 || values2.size === 0) continue;

    // Calculate overlap
    const intersection = new Set([...values1].filter(v => values2.has(v)));
    const overlapPercentage = (intersection.size / values1.size) * 100;

    // If significant overlap and col2 has higher cardinality or is unique
    if (overlapPercentage > 70 && 
        (profile2.isPotentialId || profile2.cardinalityLevel === 'unique' || profile2.uniqueCount >= profile1.uniqueCount)) {
      candidates.push({
        referencedColumn: col2,
        overlapPercentage: Math.round(overlapPercentage * 100) / 100,
        matchingValues: intersection.size
      });
    }
  }

  if (candidates.length > 0) {
    foreignKeyCandidates[col1] = candidates;
  }
}

// Add foreign key candidates to profiles
Object.keys(columnProfiles).forEach(col => {
  columnProfiles[col].foreignKeyCandidates = foreignKeyCandidates[col] || [];
});

// Return comprehensive statistics
return [{
  json: {
    columnProfiles,
    summary: {
      totalColumns: allColumns.size,
      totalRows: items.length,
      potentialIdColumns: Object.values(columnProfiles).filter(p => p.isPotentialId).map(p => p.columnName),
      foreignKeyRelationships: Object.keys(foreignKeyCandidates).length,
      profiledAt: new Date().toISOString()
    },
    rawData: items.map(item => item.json)
  }
}];

// Rules Validation Layer
// Validates the schema against business rules and data constraints

const items = $input.all();
const schemaData = items[0].json;

// Extract schema and configuration
const schema = schemaData.schema || schemaData;
const config = schemaData.config || {};
const profileData = schemaData.profileData || {};
const rawData = schemaData.rawData || [];

// Get minForeignKeyOverlap from config (default 0.7 = 70%)
const minForeignKeyOverlap = config.minForeignKeyOverlap || 0.7;

const errors = [];
const warnings = [];

// Helper function to get column values from raw data
function getColumnValues(columnName) {
  if (!rawData || rawData.length === 0) return [];
  return rawData.map(row => row[columnName]).filter(val => val !== null && val !== undefined && val !== '');
}

// Helper function to check for duplicates
function hasDuplicates(values) {
  const seen = new Set();
  for (const val of values) {
    if (seen.has(val)) return true;
    seen.add(val);
  }
  return false;
}

// Helper function to infer decimal precision from data
function inferDecimalPrecision(values) {
  let maxPrecision = 0;
  let maxScale = 0;

  for (const val of values) {
    const numStr = String(val);
    if (numStr.includes('.')) {
      const parts = numStr.split('.');
      const precision = numStr.replace('.', '').replace('-', '').length;
      const scale = parts[1].length;
      maxPrecision = Math.max(maxPrecision, precision);
      maxScale = Math.max(maxScale, scale);
    } else {
      const precision = numStr.replace('-', '').length;
      maxPrecision = Math.max(maxPrecision, precision);
    }
  }

  return { precision: maxPrecision, scale: maxScale };
}

// Helper function to check type compatibility
function checkTypeMatch(columnName, declaredType, values) {
  if (values.length === 0) return true;

  const typeChecks = {
    'INTEGER': (v) => Number.isInteger(Number(v)),
    'BIGINT': (v) => Number.isInteger(Number(v)),
    'SMALLINT': (v) => Number.isInteger(Number(v)),
    'DECIMAL': (v) => !isNaN(Number(v)),
    'NUMERIC': (v) => !isNaN(Number(v)),
    'FLOAT': (v) => !isNaN(Number(v)),
    'DOUBLE': (v) => !isNaN(Number(v)),
    'VARCHAR': (v) => typeof v === 'string' || v !== null,
    'TEXT': (v) => typeof v === 'string' || v !== null,
    'DATE': (v) => !isNaN(Date.parse(v)),
    'TIMESTAMP': (v) => !isNaN(Date.parse(v)),
    'BOOLEAN': (v) => typeof v === 'boolean' || v === 'true' || v === 'false' || v === 0 || v === 1
  };

  const baseType = declaredType.split('(')[0].toUpperCase();
  const checker = typeChecks[baseType];

  if (!checker) return true; // Unknown type, skip validation

  const mismatches = values.filter(v => !checker(v));
  return mismatches.length === 0;
}

// Helper function to get value range
function getValueRange(values) {
  const numericValues = values.map(v => Number(v)).filter(v => !isNaN(v));
  if (numericValues.length === 0) return null;
  return {
    min: Math.min(...numericValues),
    max: Math.max(...numericValues)
  };
}

// Validation 1: Check all columns exist in input data
if (schema.tables && Array.isArray(schema.tables)) {
  const availableColumns = rawData.length > 0 ? Object.keys(rawData[0]) : [];

  for (const table of schema.tables) {
    if (table.columns && Array.isArray(table.columns)) {
      for (const column of table.columns) {
        if (!availableColumns.includes(column.name)) {
          errors.push(`Column '${column.name}' in table '${table.name}' does not exist in input data`);
        }
      }
    }
  }
}

// Validation 2: Check types match actual data
if (schema.tables && Array.isArray(schema.tables)) {
  for (const table of schema.tables) {
    if (table.columns && Array.isArray(table.columns)) {
      for (const column of table.columns) {
        const values = getColumnValues(column.name);
        if (values.length > 0 && !checkTypeMatch(column.name, column.type, values)) {
          errors.push(`Column '${column.name}' type '${column.type}' does not match actual data types`);
        }
      }
    }
  }
}

// Validation 3: Check FK relationships have >70% overlapping keys
if (schema.tables && Array.isArray(schema.tables)) {
  for (const table of schema.tables) {
    if (table.foreignKeys && Array.isArray(table.foreignKeys)) {
      for (const fk of table.foreignKeys) {
        const fkValues = getColumnValues(fk.column);
        const pkValues = getColumnValues(fk.references.column);

        if (fkValues.length > 0 && pkValues.length > 0) {
          const pkSet = new Set(pkValues);
          const matchingCount = fkValues.filter(v => pkSet.has(v)).length;
          const overlapRatio = matchingCount / fkValues.length;

          if (overlapRatio < minForeignKeyOverlap) {
            errors.push(`Foreign key '${fk.column}' -> '${fk.references.table}.${fk.references.column}' has only ${(overlapRatio * 100).toFixed(1)}% overlap (minimum ${(minForeignKeyOverlap * 100)}% required)`);
          }
        }
      }
    }
  }
}

// Validation 4: Check for cycle relationships
if (schema.tables && Array.isArray(schema.tables)) {
  const buildGraph = () => {
    const graph = {};
    for (const table of schema.tables) {
      graph[table.name] = [];
      if (table.foreignKeys && Array.isArray(table.foreignKeys)) {
        for (const fk of table.foreignKeys) {
          graph[table.name].push(fk.references.table);
        }
      }
    }
    return graph;
  };

  const detectCycle = (graph) => {
    const visited = new Set();
    const recStack = new Set();
    const path = [];

    const dfs = (node) => {
      visited.add(node);
      recStack.add(node);
      path.push(node);

      if (graph[node]) {
        for (const neighbor of graph[node]) {
          if (!visited.has(neighbor)) {
            if (dfs(neighbor)) return true;
          } else if (recStack.has(neighbor)) {
            path.push(neighbor);
            return true;
          }
        }
      }

      path.pop();
      recStack.delete(node);
      return false;
    };

    for (const node in graph) {
      if (!visited.has(node)) {
        if (dfs(node)) {
          return path;
        }
      }
    }
    return null;
  };

  const graph = buildGraph();
  const cycle = detectCycle(graph);

  if (cycle) {
    errors.push(`Circular foreign key relationship detected: ${cycle.join(' -> ')}`);
  }
}

// Validation 5: Cannot choose PK for columns with duplicates
if (schema.tables && Array.isArray(schema.tables)) {
  for (const table of schema.tables) {
    if (table.columns && Array.isArray(table.columns)) {
      for (const column of table.columns) {
        if (column.primaryKey) {
          const values = getColumnValues(column.name);
          if (values.length > 0 && hasDuplicates(values)) {
            errors.push(`Column '${column.name}' is marked as primary key but contains duplicate values`);
          }
        }
      }
    }
  }
}

// Validation 6: Decimal precision inferred from data
if (schema.tables && Array.isArray(schema.tables)) {
  for (const table of schema.tables) {
    if (table.columns && Array.isArray(table.columns)) {
      for (const column of table.columns) {
        const baseType = column.type.split('(')[0].toUpperCase();
        if (baseType === 'DECIMAL' || baseType === 'NUMERIC') {
          const values = getColumnValues(column.name);
          if (values.length > 0) {
            const inferred = inferDecimalPrecision(values);
            const declaredMatch = column.type.match(/\((\d+),\s*(\d+)\)/);

            if (declaredMatch) {
              const declaredPrecision = parseInt(declaredMatch[1]);
              const declaredScale = parseInt(declaredMatch[2]);

              if (inferred.precision > declaredPrecision || inferred.scale > declaredScale) {
                warnings.push(`Column '${column.name}' declared as ${column.type} but data requires DECIMAL(${inferred.precision}, ${inferred.scale})`);
              }
            }
          }
        }
      }
    }
  }
}

// Validation 7: Check constraints match value ranges
if (schema.tables && Array.isArray(schema.tables)) {
  for (const table of schema.tables) {
    if (table.columns && Array.isArray(table.columns)) {
      for (const column of table.columns) {
        if (column.constraints && Array.isArray(column.constraints)) {
          const values = getColumnValues(column.name);
          const range = getValueRange(values);

          for (const constraint of column.constraints) {
            if (constraint.includes('>') || constraint.includes('<') || constraint.includes('BETWEEN')) {
              if (range) {
                // Extract numeric values from constraint
                const numbers = constraint.match(/\d+(\.\d+)?/g);
                if (numbers) {
                  const constraintValues = numbers.map(n => Number(n));

                  if (constraint.includes('>') && !constraint.includes('>=')) {
                    if (range.min <= constraintValues[0]) {
                      warnings.push(`Column '${column.name}' has constraint '${constraint}' but data contains values <= ${constraintValues[0]}`);
                    }
                  } else if (constraint.includes('>=')) {
                    if (range.min < constraintValues[0]) {
                      warnings.push(`Column '${column.name}' has constraint '${constraint}' but data contains values < ${constraintValues[0]}`);
                    }
                  }

                  if (constraint.includes('<') && !constraint.includes('<=')) {
                    if (range.max >= constraintValues[constraintValues.length - 1]) {
                      warnings.push(`Column '${column.name}' has constraint '${constraint}' but data contains values >= ${constraintValues[constraintValues.length - 1]}`);
                    }
                  } else if (constraint.includes('<=')) {
                    if (range.max > constraintValues[constraintValues.length - 1]) {
                      warnings.push(`Column '${column.name}' has constraint '${constraint}' but data contains values > ${constraintValues[constraintValues.length - 1]}`);
                    }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

// Determine if validation passed
const isValid = errors.length === 0;

// Return validation result
return [{
  json: {
    ...schemaData,
    validation: {
      isValid,
      errors,
      warnings,
      timestamp: new Date().toISOString()
    }
  }
}];

// Generate Production-Grade SQL DDL from Validated Schema
// This code creates comprehensive CREATE TABLE statements with all constraints

const items = $input.all();
const results = [];

for (const item of items) {
  const schema = item.json.validatedSchema || item.json.schema || item.json;
  const tables = schema.tables || [];
  const relationships = schema.relationships || [];
  const metadata = schema.metadata || {};

  let ddl = [];

  // Add header comment
  ddl.push('-- ========================================');
  ddl.push('-- Production Database Schema DDL');
  ddl.push(`-- Generated: ${new Date().toISOString()}`);
  if (metadata.fileName) {
    ddl.push(`-- Source File: ${metadata.fileName}`);
  }
  ddl.push('-- ========================================\n');

  // Generate CREATE TABLE statements
  for (const table of tables) {
    ddl.push(`-- Table: ${table.name}`);
    if (table.description) {
      ddl.push(`-- Description: ${table.description}`);
    }
    ddl.push(`CREATE TABLE ${table.name} (`);

    const columnDefs = [];
    const constraints = [];

    // Process columns
    for (let i = 0; i < table.columns.length; i++) {
      const col = table.columns[i];
      let colDef = `    ${col.name} ${col.dataType}`;

      // Add length/precision if specified
      if (col.length) {
        colDef += `(${col.length})`;
      } else if (col.precision && col.scale) {
        colDef += `(${col.precision}, ${col.scale})`;
      }

      // Add NOT NULL constraint
      if (col.nullable === false || col.required === true) {
        colDef += ' NOT NULL';
      }

      // Add DEFAULT value
      if (col.defaultValue !== undefined && col.defaultValue !== null) {
        if (typeof col.defaultValue === 'string') {
          colDef += ` DEFAULT '${col.defaultValue}'`;
        } else {
          colDef += ` DEFAULT ${col.defaultValue}`;
        }
      }

      // Add CHECK constraints
      if (col.checkConstraint) {
        colDef += ` CHECK (${col.checkConstraint})`;
      }

      // Add column comment
      if (col.description) {
        colDef += ` -- ${col.description}`;
      }

      columnDefs.push(colDef);
    }

    // Add PRIMARY KEY constraint
    const pkColumns = table.columns.filter(c => c.isPrimaryKey || c.primaryKey);
    if (pkColumns.length > 0) {
      const pkNames = pkColumns.map(c => c.name).join(', ');
      constraints.push(`    PRIMARY KEY (${pkNames})`);
    }

    // Add UNIQUE constraints
    const uniqueColumns = table.columns.filter(c => c.isUnique || c.unique);
    for (const col of uniqueColumns) {
      constraints.push(`    UNIQUE (${col.name})`);
    }

    // Combine columns and constraints
    const allDefs = [...columnDefs, ...constraints];
    ddl.push(allDefs.join(',\n'));
    ddl.push(');\n');

    // Add table indexes
    const indexedColumns = table.columns.filter(c => c.indexed || c.index);
    for (const col of indexedColumns) {
      if (!col.isPrimaryKey && !col.isUnique) {
        ddl.push(`CREATE INDEX idx_${table.name}_${col.name} ON ${table.name}(${col.name});`);
      }
    }

    if (indexedColumns.length > 0) {
      ddl.push('');
    }
  }

  // Generate FOREIGN KEY constraints
  if (relationships && relationships.length > 0) {
    ddl.push('-- Foreign Key Constraints');
    ddl.push('-- Establishing referential integrity between tables\n');

    for (const rel of relationships) {
      const fkName = `fk_${rel.fromTable}_${rel.toTable}`;
      ddl.push(`ALTER TABLE ${rel.fromTable}`);
      ddl.push(`    ADD CONSTRAINT ${fkName}`);
      ddl.push(`    FOREIGN KEY (${rel.fromColumn})`);
      ddl.push(`    REFERENCES ${rel.toTable}(${rel.toColumn})`);

      // Add ON DELETE and ON UPDATE actions
      const onDelete = rel.onDelete || 'NO ACTION';
      const onUpdate = rel.onUpdate || 'NO ACTION';
      ddl.push(`    ON DELETE ${onDelete}`);
      ddl.push(`    ON UPDATE ${onUpdate};\n`);
    }
  }

  // Add design decision comments
  ddl.push('-- ========================================');
  ddl.push('-- Design Decisions and Notes');
  ddl.push('-- ========================================');
  ddl.push('-- 1. All tables include appropriate primary keys for data integrity');
  ddl.push('-- 2. Foreign keys enforce referential integrity between related tables');
  ddl.push('-- 3. NOT NULL constraints prevent missing critical data');
  ddl.push('-- 4. Indexes created on frequently queried columns for performance');
  ddl.push('-- 5. Data types selected based on column profiling and business rules');
  if (metadata.designNotes) {
    ddl.push(`-- 6. Additional Notes: ${metadata.designNotes}`);
  }

  const sqlDDL = ddl.join('\n');

  results.push({
    json: {
      ...item.json,
      sqlDDL: sqlDDL,
      ddlGenerated: true,
      generatedAt: new Date().toISOString(),
      tableCount: tables.length,
      relationshipCount: relationships.length
    }
  });
}

return results;

