const items = $input.all();
const schemaData = items[0].json;

// Extract tables and relationships from schema
const tables = schemaData.schema?.tables || [];
const relationships = schemaData.schema?.relationships || [];

// Build dependency graph
function buildDependencyGraph(tables, relationships) {
  const graph = {};
  const inDegree = {};

  // Initialize graph with all tables
  tables.forEach(table => {
    graph[table.name] = [];
    inDegree[table.name] = 0;
  });

  // Build edges based on foreign key relationships
  relationships.forEach(rel => {
    if (rel.type === 'foreign_key') {
      // Child table depends on parent table
      const childTable = rel.from_table;
      const parentTable = rel.to_table;

      if (graph[parentTable] && !graph[parentTable].includes(childTable)) {
        graph[parentTable].push(childTable);
        inDegree[childTable]++;
      }
    }
  });

  return { graph, inDegree };
}

// Topological sort to determine load order
function topologicalSort(graph, inDegree) {
  const queue = [];
  const result = [];
  const visited = new Set();

  // Find all nodes with no dependencies
  Object.keys(inDegree).forEach(table => {
    if (inDegree[table] === 0) {
      queue.push(table);
    }
  });

  while (queue.length > 0) {
    const current = queue.shift();
    result.push(current);
    visited.add(current);

    // Process dependent tables
    (graph[current] || []).forEach(dependent => {
      inDegree[dependent]--;
      if (inDegree[dependent] === 0) {
        queue.push(dependent);
      }
    });
  }

  return result;
}

// Detect circular dependencies
function detectCircularDependencies(tables, sortedOrder) {
  const circular = [];
  tables.forEach(table => {
    if (!sortedOrder.includes(table.name)) {
      circular.push(table.name);
    }
  });
  return circular;
}

// Generate batch recommendations
function generateBatchRecommendations(sortedOrder, tables) {
  const batches = [];
  let currentBatch = [];

  sortedOrder.forEach((tableName, index) => {
    const table = tables.find(t => t.name === tableName);
    currentBatch.push(tableName);

    // Create batches of 5 tables or at natural dependency breaks
    if (currentBatch.length >= 5 || index === sortedOrder.length - 1) {
      batches.push([...currentBatch]);
      currentBatch = [];
    }
  });

  return batches;
}

// Generate Mermaid diagram for dependency visualization
function generateDependencyDiagram(graph, sortedOrder) {
  let mermaid = 'graph TD\n';

  sortedOrder.forEach(table => {
    const dependencies = graph[table] || [];
    if (dependencies.length === 0) {
      mermaid += `  ${table}[${table}]\n`;
    } else {
      dependencies.forEach(dep => {
        mermaid += `  ${table}[${table}] --> ${dep}[${dep}]\n`;
      });
    }
  });

  return mermaid;
}

// Build the dependency graph
const { graph, inDegree } = buildDependencyGraph(tables, relationships);

// Get topological sort order
const loadOrder = topologicalSort(graph, JSON.parse(JSON.stringify(inDegree)));

// Detect circular dependencies
const circularDeps = detectCircularDependencies(tables, loadOrder);

// Generate batch recommendations
const batches = generateBatchRecommendations(loadOrder, tables);

// Generate dependency diagram
const dependencyDiagram = generateDependencyDiagram(graph, loadOrder);

// Create detailed load plan
const loadPlan = {
  load_order: loadOrder,
  total_tables: tables.length,
  batches: batches.map((batch, index) => ({
    batch_number: index + 1,
    tables: batch,
    description: `Load batch ${index + 1} - ${batch.length} table(s)`
  })),
  circular_dependencies: circularDeps.length > 0 ? {
    detected: true,
    tables: circularDeps,
    resolution_strategy: "Disable foreign key constraints temporarily, load data, then re-enable constraints"
  } : {
    detected: false,
    message: "No circular dependencies detected"
  },
  dependency_graph: dependencyDiagram,
  recommendations: [
    "Load tables in the specified order to satisfy foreign key constraints",
    "Use batch processing for large datasets (recommended batch size: 1000-5000 rows)",
    "Disable indexes before bulk load and rebuild after completion for better performance",
    "Use transactions for each batch to ensure data consistency",
    circularDeps.length > 0 ? "Handle circular dependencies by temporarily disabling FK constraints" : "No circular dependencies to handle",
    "Validate data integrity after load completion",
    "Consider parallel loading for independent tables (tables with no dependencies)"
  ],
  insertion_strategy: {
    independent_tables: loadOrder.filter(table => inDegree[table] === 0),
    dependent_tables: loadOrder.filter(table => inDegree[table] > 0),
    parallel_load_possible: loadOrder.filter(table => inDegree[table] === 0).length > 1
  }
};

// Return the load plan
return [{
